var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"저것 좀 봐. 쟤 또 물건 망가트렸어.","JPN":"ほら、あれ見てみなよ。あいつ、また物を壊したよ。","ENG":"Look at that. She ruined it again.","TWN":"你看啦，那傢伙又把東西弄壞了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"케이시는 카운터라며? 카운터랑은 살짝 부딪히기만 해도 병원에 실려간대.","JPN":"ケイシーはカウンターなんでしょ？　カウンターとはちょっとぶつかっただけでも入院って聞いた。","ENG":"Kaci's a Counter, right? They say if you bump into a Counter that you get sent to the hospital.","TWN":"卡西不是制裁者嗎？聽說只要稍微撞到制裁者，就會被送進醫院。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"가까이 가지 말자. 같이 있으면 우리도 다칠 거야.","JPN":"近付いちゃだめ。一緒にいたら、私たちも怪我するよ。","ENG":"Let's stay away from her. If we play with her, we'll get hurt too.","TWN":"別靠近她啦，跟她在一起我們也會受傷。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"케이시, 이건 모두 널 위해 결정된 거란다.","JPN":"ケイシー、これは全部あなたのための決定なの。","ENG":"Kaci, this is all for your own good.","TWN":"卡西，這一切都是為了你好才做的決定。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"네가 실수로라도 친구들을 다치게 한다면… 너도 많이 힘들어질 테니까. 이해하지?","JPN":"ケイシーが間違って友だちを傷つけてしまったら……きっと、自分自身にも耐えられなくなると思うの。わかってもらえるよね？","ENG":"If you accidentally hurt your friends... it'll become difficult for you too. Do you understand?","TWN":"要是你不小心傷到朋友……你自己也會很痛苦，懂嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"전 괜찮아요.","JPN":"あたしは大丈夫です。","ENG":"I'm all right.","TWN":"我沒關係。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 누구도 다치게 하지 않아.","JPN":"あたしは誰も傷つけない。","ENG":"I don't hurt anyone.","TWN":"我不會傷害任何人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"이것 봐. 이렇게 연약한 식물들도 전부 잘 키워냈는걸?","JPN":"ほら、こんなに弱い植物だって上手に育ててみせたもの。","ENG":"Look at this. I managed to take care of and grow all these plants!","TWN":"你看，就連這麼脆弱的植物，我也都好好地養大了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"어쩌면… 이대로 아무도 몰라줘도 괜찮을 거야.","JPN":"もしかすると……このまま誰にもわかってもらえないかもしれないけど、大丈夫。","ENG":"Maybe... It doesn't matter if no one understands me.","TWN":"或許……就算沒有人理解我也沒關係。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게 예쁘게 피어난 꽃들이… 내 마음을 이해해주고 있으니까.","JPN":"こんなに綺麗に咲き誇った花たちが……あたしの気持ちを理解してくれている。","ENG":"These beautifully bloomed flowers... they get me.","TWN":"因為這些盛開得如此漂亮的花……它們懂我的心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"파견 실습…?","JPN":"派遣実習……？","ENG":"On-the-job training...?","TWN":"派遣實習……？"},"stage":{"bg":"CLASS","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그래! 브라우니 선생님이 이번엔 태스크포스 견학이 아니라 실습생으로 가는 거래!","JPN":"そう！　ブラウニー先生に聞いたけど、今回はタスクフォースの見学じゃなくて実習なんだって！","ENG":"Yup! Ms. Brownie said that someone will go to a TASKFORCE as a trainee and not just for a tour!","TWN":"對啊！布朗尼老師這次不是去參觀特遣勢力，而是要去實習！"},"stage":{"bg":"CLASS","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"초등부에선 딱 한 명만 선발한다니까, 이건 두 번 다신 없을 기회라구, 케이시!","JPN":"初等部では1人しか選抜しないって！　つまり、絶好のチャンスってことだよ、ケイシー！","ENG":"They are selecting only one person from the elementary school, so this is a once in a lifetime chance, Kaci!","TWN":"而且小學部只選一個人，這可是一輩子只有一次的機會耶，卡西！"},"stage":{"bg":"CLASS","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"정말로… 내가 그런 곳에 가는 게 도움이 될까?","JPN":"本当に……あたしがそんなとこに行って役に立つかな？","ENG":"But will I... be of any help over there?","TWN":"我去那種地方……真的能幫上忙嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"물론이지! 히어로가 되려면 연습보단 실전 경험이 중요한 법이니까!","JPN":"もちろん！　ヒーローになるためには、練習よりも実戦の経験が大事って言うじゃん！","ENG":"Of course, you will! Experience is more important than practice if you want to become a hero!","TWN":"當然會啊！如果要成為英雄，比起練習，實戰經驗最重要了！"},"stage":{"bg":"CLASS","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그렇게 해서, 우리 데이마인에 일일 파견 실습생으로 오게 된 아카데미의 케이시 빈즈 학생이다.","JPN":"というわけで、アカデミーからこのデイマインに一日実習生として派遣された、ケイシー・ビンズさんだ。","ENG":"And so, Academy's Kaci Bins will be here with us at Daymine as a one-day trainee.","TWN":"那麼，這位就是今天來到我們戴瑪因擔任一日派遣實習生的學院學生卡西‧比恩茲。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기… 잘 부탁드립니다.","JPN":"あの……よろしくお願いします。","ENG":"Uh... Pleased to meet you all.","TWN":"那個……請多指教。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"와아, 이렇게 키 작고 귀여운 꼬마애가 저희 회사의 일일 사원이라니- 너무 좋은데요?","JPN":"わあ、こんなに小さくて可愛い子どもがうちの一日社員だなんて！　嬉しいです！","ENG":"Wow! This little cutie pie is going to be an employee at our company for the day? That's wonderful!","TWN":"哇，這麼小隻又可愛的孩子，竟然是我們公司的臨時員工，也太棒了吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"그렇게 말씀을 함부로 하시면 곤란합니다, 소미 씨! 키가 작다거나, 귀엽다는 표현을 직접적으로 쓰면 불쾌해하는 분도 계시다고요!","JPN":"ミウラさん、言葉には気をつけましょう。小さいとか可愛いという表現を不快に思う方もいるんですから！","ENG":"You shouldn't talk to her like that, Somi! Some people might be offended if they are called little or cute!","TWN":"請不要這樣隨便亂說，小美小姐！直接說人家小隻或可愛，有些人會感到不舒服！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"으왓…! 그렇다면 방금 전 엄청난 실례를 한 건가요?!","JPN":"うわ……！　じゃあ私は今とんでもない失言をしたんですか！？","ENG":"Oops...! Then, was I incredibly rude just now?!","TWN":"嗚哇……！那我剛剛是不是超級失禮了？！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아뇨. 전 키가 작은 게 맞는 걸요.","JPN":"いえ、あたしが小さいのは本当ですし。","ENG":"No. It's true that I'm little.","TWN":"沒關係，我本來就很矮。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"귀엽다는 표현도… 칭찬이라고 생각해요.","JPN":"可愛いという表現も……褒め言葉だと思います。","ENG":"And I think being called cute is... a compliment.","TWN":"可愛這個詞……我也覺得是稱讚。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"휴우… 그렇다면 다행입니다.","JPN":"ふう……それならよかったです。","ENG":"Phew... That's a relief.","TWN":"呼……那就好。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"하하- 제 늦둥이 사촌 여동생도 딱 이 정도 나이인데, 정말 깜찍하다니까요.","JPN":"はは、僕の従妹もちょうど同じぐらいの年齢で、本当に可愛いんですよ。","ENG":"Haha, my youngest cousin is around your age, and she's just the cutest.","TWN":"哈哈—我最小的表妹也差不多這個年紀，真的超可愛的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"헤헤- 언니랑 사탕 먹으러 갈까?","JPN":"えへへ、お姉ちゃんと一緒にアメ食べない？","ENG":"Hehe, do you want to go get a lollipop with me?","TWN":"嘿嘿—要不要跟姐姐去吃糖果？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 저기…","JPN":"あ……えっと……","ENG":"Uh... Um...","TWN":"啊……那個……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"정신 차려. 지금은 업무시간이다.","JPN":"おしゃべりはそのくらいで。今は業務時間だ。","ENG":"Stop fooling around. You're on the clock.","TWN":"正經點，現在是上班時間。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그리고 케이시 빈즈 학생은 우리랑 같은 사원 신분으로 일하는 거니까, 대놓고 어린애 취급하지 마.","JPN":"それにケイシー・ビンズさんは、私たちと同じ社員として働く立場だ。子ども扱いもやめるように。","ENG":"Also, Kaci Bins is here as an employee, so don't treat her like a child.","TWN":"而且卡西‧比恩茲同學是以和我們一樣的員工身分工作，別把她當小孩。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"앗, 네엡! 죄송합니다!","JPN":"あっ、はい！　すみません！","ENG":"Yes, sir! My apologies!","TWN":"啊、是的！很抱歉！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"받아요, 케이시 후배.","JPN":"どうぞ、ケイシーさん。","ENG":"Here you go, Kaci.","TWN":"來，卡西後輩。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"우리 탕비실의 명물 따뜻한 코코아에요.","JPN":"うちの給湯室の名物、ホットココアです。","ENG":"This is our company break room's special hot cocoa.","TWN":"這是我們茶水間的招牌熱可可亞。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 감사합니다.","JPN":"あ……ありがとうございます。","ENG":"Oh... Thank you.","TWN":"啊……謝謝你。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런데… 이렇게 앉아있어도 괜찮은 건가요?","JPN":"それにしても……こうして座りっぱなしで大丈夫ですか？","ENG":"But... Are we allowed to be sitting here like this?","TWN":"可是……我就這樣坐著，真的沒問題嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"네? 보통은 앉아있는 쪽이 편하지 않나요?","JPN":"え？　普通は座っているほうが楽じゃないですか？","ENG":"Hmm? But isn't it more comfortable to be sitting down?","TWN":"咦？通常不是坐著比較輕鬆嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아, 우리 케이시 후배는 산책을 좋아하는 타입?","JPN":"あ、ケイシーさんはもしかして散歩が好きなタイプ？","ENG":"Oh, are you the type that likes going on walks?","TWN":"啊，我們卡西後輩是喜歡到處走走的類型啊？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으음… 어른 카운터들이 있는 태스크포스니까… 도시로 출동해서 악당하고 싸운다거나…","JPN":"うーん……大人のカウンターさんがいるタスクフォースですから……都心に出動して、悪党と戦ったり……","ENG":"Mm... Since this is a TASKFORCE with adult Counters... don't you patrol the city and fight villains...?","TWN":"嗯……既然是成年制裁者的特遣勢力……我以為會去城市對付壞人……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"악당…?","JPN":"悪党……？","ENG":"Villains...?","TWN":"壞人……？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"뭐 그런 대단하고 멋진 일까진 아니지만, 저희도 도시를 위해서 일을 하긴 하죠.","JPN":"まあ、そこまで格好いい仕事ではないかもしれないけど、私たちもこの都市のために働いているんですよ。","ENG":"Well, we don't do anything as cool as that, but we still do work to protect the city.","TWN":"雖然沒有那麼了不起跟帥氣啦，但我們確實是在為城市工作。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"으왓, 깜짝아!","JPN":"うわっ、びっくりした！","ENG":"Whoa!","TWN":"哇！嚇我一跳！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"후배 여러분! 출동 시간입니다!","JPN":"後輩の皆さん！　出動する時間です！","ENG":"Okay, everyone! It's time to go out!","TWN":"各位後輩！出動時間到了！"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"읏샤-","JPN":"よいっしょっと。","ENG":"Errsha!","TWN":"嘿咻—"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"케이시 후배, 그쪽은 어때요?","JPN":"ケイシーさん、そっちはどうですか？","ENG":"Kaci, how's it going over there?","TWN":"卡西後輩，那邊情況如何？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네, 말씀하신대로 백걸음 마다 깃발 하나씩. 전부 꽂았어요.","JPN":"言われたとおり、100歩に旗を1個。全部立てました。","ENG":"Oh, I've planted a flag for every one hundred steps like you told me to.","TWN":"是的，照您說的每走一百步插一面旗子，全都插完了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"고생 많았어요. 그럼 좀 쉬도록 하죠.","JPN":"お疲れ様です。じゃあ少し休憩にしましょう。","ENG":"Good job. You can take a break now.","TWN":"辛苦了，先休息一下吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"…미안해요, 후배님. 현장일이라는 게 기대했던 것보다 별로 보람도 없고 시시하죠?","JPN":"……ごめんなさいね。現場の仕事って、期待したのと違ってあまりやりがいもないし、つまらないですよね。","ENG":"...I'm sorry, Kacy. Field work is boring and less rewarding than you expected, isn't it?","TWN":"……對不起啊，後輩。現場工作是不是比想像中無聊，也沒什麼成就感？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아뇨, 충분히 보람 있었어요.","JPN":"いいえ、十分やりがいのある仕事でした。","ENG":"No, it was rewarding.","TWN":"不會，我覺得很有成就感。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"이 밖으로 나가면 침식파 때문에 위험하다고, 깃발로 사람들에게 알려주는 일이니까요.","JPN":"ここに旗を立てることで、ここから外に出たら侵食波のせいで危険ですよって皆に知らせることができますから。","ENG":"The flags are there to tell people that it's dangerous due to Corruption rays beyond this point.","TWN":"因為我們這是在用旗幟告訴大家，出去後會有侵蝕波很危險。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아하하, 그렇게 생각해주니 다행이네요.","JPN":"あはは、そう思ってもらえて嬉しいです。","ENG":"Ah hah hah. Well, I'm glad you think of it like that.","TWN":"哈哈，你能這樣想真是太好了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…실은 안심했어요.","JPN":"……実は安心しました。","ENG":"...To be honest, I'm more relieved.","TWN":"……其實我鬆了一口氣。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기 오기 전에는 무서운 침식체나 악당들하고 싸우게 될 줄 알고 걱정했거든요.","JPN":"ここに来る前は、怖い侵食体とか悪党と戦うことになるのかなと思って心配してたんです。","ENG":"I was worried that I would be fighting scary C.O.s before coming here.","TWN":"我在來之前還以為會跟可怕的侵蝕體或壞人戰鬥，緊張死了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"걱정마요. 그렇게 된다고 해도 케이시 후배한테 그런 위험한 일은 시키지 않을 테니까.","JPN":"心配はいりませんよ。もしそんなことがあっても、ケイシーさんにはそういう危険な仕事はやらせませんから。","ENG":"Don't worry. Even if that were to happen, we wouldn't put you in such danger.","TWN":"放心吧，就算真的那樣，也不會讓卡西後輩做那麼危險的事。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그리고 케이시 후배 정도면 용감한 거죠! 어린 나이에도 이렇게 직접 자원해서 왔잖아요?","JPN":"それにケイシーさんは十分勇敢ですよ。まだ若いのに、自分の意思でここに来たんでしょう？","ENG":"And you're also brave, Kaci! You're still young, but you decided to volunteer to come here, didn't you?","TWN":"而且，卡西後輩已經很勇敢了！這麼小就主動報名了不是嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기에 오게 된 것도… 제가 결정한 게 아니라 친구가 등을 밀어줬기 때문인 걸요.","JPN":"ここに来たのも……自分で決めたんじゃなくて、友だちに背中を押してもらったからなんです。","ENG":"The reason I came here... wasn't my decision, but because my friend said I should do it.","TWN":"我會來這裡……其實也是朋友在背後推了我一把。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"전 힘만 센 겁쟁이에요.","JPN":"あたしは力が強いだけの臆病者です。","ENG":"I'm just a strong coward.","TWN":"我只是個力氣大的膽小鬼。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"하지만, 결국 도망치지 않았잖아요?","JPN":"でも結果的に、逃げなかったじゃないですか？","ENG":"But you didn't run away.","TWN":"但你最後沒有逃走，對吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"친구가 등을 밀어줬으니까. 그 기대를 저버리지 않기 위해서 여기까지 온 거죠?","JPN":"友だちに背中を押してもらって、その期待を裏切りたくなくてここまで来たんですよね。","ENG":"Your friend might have pushed you to come here, but you still came because you didn't want to disappoint, right?","TWN":"因為朋友推了你一把，你不想辜負那份期待，所以才來到這裡對吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"전 그것만으로도 충분히, 케이시 후배가 대견하단 생각이 드는데요?","JPN":"私はそれだけでも十分、ケイシーさんは偉いと思いますよ？","ENG":"I think that's enough to make me be proud of you.","TWN":"光是這樣，我就覺得卡西後輩已經很了不起了耶？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"정말… 그런 걸로 괜찮은 걸까요?","JPN":"本当に……それでいいんでしょうか？","ENG":"Is that... really enough?","TWN":"真的……這樣就夠了嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"헤헤, 그럼요.","JPN":"えへへ、もちろんです。","ENG":"Hehe, of course!","TWN":"嘿嘿，當然囉。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"저도 지금은 회사에서 커피를 타고, 이정표를 박는 일을 하는 신입사원이지만…","JPN":"私も今は会社でコーヒーを淹れたり、旗を立てる仕事をやるぐらいの新入りですけど……","ENG":"I might be a new employee who makes coffee and plants signposts...","TWN":"我現在也只是個在公司泡咖啡、插路標的新進員工……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"언젠가는 사람들을 가르쳐주고 이끌어주는 듬직한 선배 직장인이 될 거예요.","JPN":"いつかはみんなに教えてあげたり導いてあげる、頼もしい先輩になりたいと思ってます。","ENG":"but one day, I'm going to become a reliable professional who teaches and guides others.","TWN":"但總有一天，我會成為能教導、引領他人的可靠前輩。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"지금 당장 미숙한 신입사원이라고 해서, 나 자신을 틀렸다고 말할 필요는 없는 거죠.","JPN":"今の自分が未熟な新入りだからって、自分を否定する必要はないんです。","ENG":"Just because I'm inexperienced now doesn't mean that I have to tell myself that I'm wrong.","TWN":"你不需要因為現在還不成熟，就否定自己。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"심소미, 잡담 그만하고 빨리 2구역 작업 들어가라.","JPN":"ミウラ君、雑談はそのへんにして早く2区域の作業に入りなさい。","ENG":"Shim Somi, enough chatting and get to work in Zone 2.","TWN":"沈小美，別聊天了，快去2區作業。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"에…?","JPN":"え……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"앗…? 이거? 공용채널…? 어, 언제부터 통신이 켜져 있었던 거죠?","JPN":"あっ……？　これ、共用チャンネル……？　い、いつから通信が繋がってたんですか？","ENG":"Oh...? Was this... a public channel...? Uh, since when were my comms on?","TWN":"啊……？！這個？是共用頻道……？什、什麼時候打開的？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"크흑… 후배님. 그런 멋진 말씀을 하시다니. 저, 감동했습니다!","JPN":"うっ……ミウラさん、そんなカッコいいことを言って……僕、感動しました！","ENG":"Kgh... Somi. Your heartfelt words have moved me!","TWN":"嗚……前輩居然說了那麼帥氣的話，我好感動！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"좋아요! 우리 모두 함께 사람들을 이끌어주는 멋진 선배가 되자고요!","JPN":"いいでしょう！　人々を導く素敵な先輩に、一緒になりましょう！","ENG":"Okay! Let's all do our best to become professionals who guide others!","TWN":"太好了！我們一起成為能引領大家的帥氣前輩吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"흐에엑…? 으아아아…?!","JPN":"ふええ……？　ああああ……？","ENG":"Huh...?! Whaaaat...?!","TWN":"欸欸欸……？！啊啊啊……？！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"취소! 취소! 부디 못 들은 걸로 주시면 안 될까요? 네?","JPN":"い、今のは無し！　どうか聞かなかったことにしてください！！","ENG":"Nope! Nope! Could you all pretend you didn't hear that? Please?","TWN":"取消！取消！拜託當作沒聽到好嗎？嗯？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"아, 그래. 우린 아무것도 못 들었다.","JPN":"はい、はい。私たちは何も聞いてないぞ。","ENG":"All right. We heard nothing.","TWN":"啊，是啊，我們什麼都沒聽到。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"….으하아아앙!!!","JPN":"……わあああん！！","ENG":"...WAAAAAAH!!!","TWN":"……嗚哇啊啊啊！！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"역시… 친구 말을 듣고 오길 잘 한 것 같아요.","JPN":"やっぱり……友だちに言われたとおり、来てよかったと思います。","ENG":"I'm glad... that I listened to my friend.","TWN":"果然……聽朋友的話來這裡，真是太好了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"…네?","JPN":"……え？","ENG":"...Hmm?","TWN":"……咦？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저… 선배님께서 해주신 말씀 잊지 않을게요.","JPN":"あたし……先輩の言葉忘れません。","ENG":"Um... I won't forget what you said to me today.","TWN":"那個……前輩剛剛說的話，我不會忘記的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"고맙습니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"으흑흑… 후배님에게 도움이 됐다니, 그나마 위안이 되네요.","JPN":"ううう……ケイシーさんの役に立てたようで、私の心も少しは慰められます。","ENG":"*Sniffle* It's comforting to know that I've been of help to you, Kacy.","TWN":"嗚嗚……能幫上後輩一點忙，就讓我安心了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"저희는 이 시간에 특별한 업무가 없으면 항상 거리를 순찰합니다.","JPN":"この時間帯は、特別な任務がない限り、常に街を巡回しています。","ENG":"We always patrol the streets unless some special tasks come up.","TWN":"如果沒有特別任務，我們通常都會在街上巡邏。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"시민들의 안전을 직접 점검하고, 또 카운터가 시민들을 가까운 곳에서 돕고 있다는 걸 알려주는 거죠.","JPN":"市民たちの安全を直接確認できますし、カウンターが市民たちの身近にいるということを知らせることができるんです。","ENG":"We check the safety of the citizens and let them know that a Counter is close by and willing to help them.","TWN":"直接確認市民的安全，也讓大家知道制裁者正在身邊守護著他們。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"멋져요. 꼭 도시를 지키는 히어로 같아요.","JPN":"素敵です。まるで都市を守るヒーローみたい。","ENG":"That's so cool. You're like a hero protecting this city.","TWN":"好厲害，就像守護城市的英雄一樣。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"하하, 다른 시민 분들도 후배님처럼 생각해준다면 좋겠네요.","JPN":"ははは、市民の皆さんにもそう思っていただけると嬉しいですね。","ENG":"Haha, I only wish the citizens also thought of us like you have.","TWN":"哈哈，要是其他市民也能這麼想就好了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"카운터가 가진 힘은 위험한 무기가 아니라 시민들을 도울 수 있는 힘이라는 걸… 저도 많은 사람들이 알아주길 바라거든요.","JPN":"カウンターの力は危険な武器ではなく、市民を助けることができる力だと……もっと多くの人に知ってもらいたいので。","ENG":"I want to let people know... that a Counter's power is not a dangerous weapon, but a force to help citizens.","TWN":"我也希望有更多人知道……制裁者的力量不是危險的武器，而是能幫助人的力量。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네, 저도 그렇게 생각해요.","JPN":"はい、あたしもそう思います。","ENG":"Yes, I think so too.","TWN":"嗯，我也是這麼想的。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"누, 누가 좀…!","JPN":"だ、誰か！！","ENG":"S-somebody...!","TWN":"救、救命……！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"방금… 어떤 목소리가…","JPN":"今、声が……","ENG":"I think I heard... a cry for help...","TWN":"剛剛……是不是有聲音……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"네? 갑자기 왜 그러시죠?","JPN":"ん？　急にどうしましたか？","ENG":"Huh? What's wrong?","TWN":"怎麼了？怎麼突然這樣？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"작지만… 분명히 도와 달라는 목소리가 들렸어요.","JPN":"小さいけど……確かに助けを求める声が聞こえました。","ENG":"It's faint, but... I'm sure I heard someone calling for help.","TWN":"雖然很小聲……但我確實聽到有人在求救。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"혹시, 그 목소리가 어느 쪽에서 들렸는지 알 수 있습니까?","JPN":"その声、どこから聞こえたかわかりますか？","ENG":"Could you tell me which direction it was from?","TWN":"你知道聲音是從哪個方向傳來的嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄아악! 옥상에 누가 매달려 있어!","JPN":"きゃああ！　屋上に人がぶら下がってる！","ENG":"Kyaaah! Someone is hanging from the rooftop!","TWN":"啊啊啊！有人掛在屋頂！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"신고했으니 조금만 버텨요!","JPN":"今通報したから！　もう少しだけ耐えて！！","ENG":"I've called for help, so hang on!","TWN":"我已經報警了，請再撐一下！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"목소리…! 저기예요!","JPN":"声……！　あそこです！","ENG":"The voice...! It's from over there!","TWN":"聲音……！是那邊！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"이런! 공사장 난간에 사람이…!","JPN":"くっ……！　工事現場の手すりに人が……！","ENG":"Look! A person is hanging on the railing at the construction site...!","TWN":"糟了！工地欄杆上有人……！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WORKER_NPC_CONST_NULL","text":{"KOREA":"으윽… 무리야.","JPN":"うぐっ……無理だ。","ENG":"Ngh... I can't...","TWN":"呃……不行。"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WORKER_NPC_CONST_NULL","text":{"KOREA":"더… 더는 못 버티겠…","JPN":"こ、これ以上は……もたな……","ENG":"I can't... hold on... any longer–","TWN":"我……撐不住了……"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WORKER_NPC_CONST_NULL","text":{"KOREA":"으아아아아악!!!","JPN":"うわああああっ！！","ENG":"AAAAACK!","TWN":"啊啊啊啊啊！！！"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"떠… 떨어진다!","JPN":"お……落ちる！！","ENG":"H-he's falling!","TWN":"掉……掉下來了！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"세상에! 어떡해!","JPN":"そんな……どうしよう！！","ENG":"Oh, no! What do we do?!","TWN":"天啊！怎麼辦！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"이런… 달려가기엔 거리가…!","JPN":"しまった……遠すぎて間に合わない……！","ENG":"Dammit...! It's too far from here–!","TWN":"糟了……跑過去的話，距離……！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"선배님! 저를 저쪽으로 던져주세요!","JPN":"先輩！　あたしをあそこに投げてください！","ENG":"Sir! Throw me over there!","TWN":"前輩！請把我拋過去！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"예…?","JPN":"え……？","ENG":"What...?","TWN":"嗯……？！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"…알겠습니다!","JPN":"……わかりました！","ENG":"...All right!","TWN":"……好！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"부디 조심하세요! 후배님!","JPN":"気をつけてください、ケイシーさん！","ENG":"Be careful! Kaci!","TWN":"請一定要小心！後輩！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하아아앗!!","JPN":"はあああっ！！","ENG":"Haaaaa!!!!","TWN":"哈啊啊啊！！"},"stage":{"bg":"DOCK_DAY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"난, 겁쟁이에 소심하니까… 사람들을 구하는 히어로 같은 건 될 수 없어.","JPN":"あたしは臆病者で小心者だから……人を助けるヒーローになんてなれない。","ENG":"I'm a coward and timid... so I can't become a hero who saves people.","TWN":"我又膽小又懦弱……本來以為自己不可能成為拯救他人的英雄。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런 걱정을 하는 동안... 난 어느새 하늘을 날고 있었어.","JPN":"そんなことで悩んでいたら……いつの間にかあたしは空を飛んでいた。","ENG":"But while I was worried about that... I was already flying through the sky.","TWN":"可是在擔心的那一刻……我已經飛在空中了。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"팔을 뻗어서 떨어지는 사람을 붙잡았을 때… 사실 무서운 생각이 들었어.","JPN":"手を伸ばして、落ちてくる人を捕まえた時……正直怖かった。","ENG":"When I reached out my hand to grab the falling man... I was scared.","TWN":"伸手抓住墜落的人時……其實我也很害怕。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"내가 너무 힘을 줘서 다치게 하진 않을까...? 실수로 놓치진 않을까…? 같은 생각 말이야.","JPN":"力を入れすぎて怪我をさせるんじゃないかとか……間違えて離してしまうんじゃないかとか。","ENG":"Scared that I might hurt him by grabbing him too hard... Or even letting go of him by mistake...","TWN":"擔心會不會太大力傷到他……？會不會不小心放手……？"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"다행히 그 사람은 무사했어. 착지하면서 발을 좀 삐끗하긴 했지만... 괜찮아. 나 엄청 튼튼하니까.","JPN":"あの人は無事だった。着地した時足をくじいてしまったけど……大丈夫。あたしは丈夫だから。","ENG":"Fortunately, he was safe. Although I sprained my ankle while landing... I was all right. Because I'm super strong.","TWN":"幸好那個人平安無事。雖然落地時稍微扭到腳……但沒關係，我很強壯。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아저씨는 고맙다고 했어. 내 덕분에 집으로 돌아가 가족들을 볼 수 있다면서.","JPN":"おじさんにありがとうって言われた。おかげで家に帰って、家族の顔がまた見れるって。","ENG":"The man thanked me, saying that he was able to go home and see his family because I saved him.","TWN":"那位大叔向我道謝，說多虧了我，才能回家與家人重逢。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"나도… 누군가를 도울 수 있구나.","JPN":"あたしにも……誰かを助けることができるんだ。","ENG":"It turns out... that I can help others.","TWN":"原來……我也能幫助別人。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"내가 용기를 내면… 그런 희망을 줄 수 있구나.","JPN":"勇気を出せば……人に希望を与えることができるんだ。","ENG":"If I have the courage... I can give hope to them.","TWN":"只要我鼓起勇氣……就能帶給別人希望。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"내가 이런 힘을 가지고 있어서… 그래서 다행이라고 생각했어. 처음으로.","JPN":"あたしにこんな力があってよかった……と、初めて思ったの。","ENG":"I was glad… that I have this power. For the first time.","TWN":"我第一次覺得自己擁有這份力量……真是太好了。"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"POLEARM_01","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"있지, 레오나르도.","JPN":"ねえ、レオナルド。","ENG":"You know, Leonardo.","TWN":"對了，萊奧納多。"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"나 가면카운터처럼 항상 용감한 히어로는 되기 힘들겠지만…","JPN":"あたし、仮面カウンターみたいにいつも勇敢なヒーローにはなれないけど……","ENG":"I might not always be as courageous a hero as the Masked Counter...","TWN":"我或許沒辦法成為像蒙面制裁者那種，永遠都會勇敢的英雄……"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그래도 어쩌다 한 번쯤은… 그런 용기를 낼 수 있는 걸지도 몰라.","JPN":"それでも、たまには……そんな勇気が出せるかもしれない。","ENG":"But maybe once every now and then... I can muster up the courage to be one.","TWN":"但也許偶爾一次……我也能鼓起那樣的勇氣。"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"매번 다시 피어나는 꽃봉오리처럼… 한 번 풀이 죽은 걸로 시들진 않은 거야.","JPN":"何度も咲いてくる花のつぼみのように……一度しおれても、枯れることはないんだ。","ENG":"Like a flower bud that blooms each year... I won't wither just because I wilted before.","TWN":"就像一次一次重新綻放的花苞……不會因為一時失意就枯萎。"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"꾸준히 노력하다보면… 언젠가 날 무서워하던 아이들도 분명 내 마음을 알아줄 테니까.","JPN":"努力を続けたら……いつかは、あたしを怖がっていた子たちも、きっとあたしの気持ちをわかってくれるだろうから。","ENG":"Maybe if I keep trying... the kids who were afraid of me will one day begin to understand me.","TWN":"只要持續努力……總有一天那些曾經害怕我的孩子，也會明白我的真心。"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까… 올해도, 내년에도…","JPN":"だから……今年も、来年も……","ENG":"So... keep blooming beautifully to support me...","TWN":"所以……今年，還有明年……"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"예쁜 꽃을 피워서 날 응원해줘.","JPN":"きれいな花を咲かせて、あたしを応援してね。","ENG":"This year... and the next.","TWN":"請繼續綻放美麗的花朵，為我加油吧。"},"stage":{"bg":"POLEARM_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};